create table users (id uuid primary key, email text unique, created_at timestamptz default now());
create table candidate_profiles (id uuid primary key, external_id text unique, user_id uuid references users(id), profile jsonb not null, created_at timestamptz default now(), updated_at timestamptz default now());
create table career_evidence (id uuid primary key, candidate_profile_id uuid references candidate_profiles(id), source_type text not null, source_ref text, excerpt text not null, confidence numeric not null);
create table jobs (id text primary key, source text not null, source_url text unique not null, company text not null, title text not null, location text, description text not null, salary_min integer, salary_max integer, active boolean default true, raw jsonb, listing jsonb, fetched_at timestamptz default now());
create table job_matches (candidate_profile_id uuid references candidate_profiles(id), job_id text references jobs(id), scores jsonb not null, overall_score numeric not null, recommendation text not null, match jsonb, created_at timestamptz default now(), primary key(candidate_profile_id, job_id));
create table applications (id uuid primary key, application_key text unique, candidate_profile_id uuid references candidate_profiles(id), job_id text references jobs(id), package jsonb not null, status text not null, approved_at timestamptz, submitted_at timestamptz, created_at timestamptz default now());
create table consent_records (id uuid primary key, application_id uuid references applications(id), action text not null, consented_at timestamptz default now(), metadata jsonb);
